// The number we want to multiply
const multiplier: number = 3;
// Loop from 1 to 10 (inclusive)
// Initial: i = 1, Condition: i <= 10, Update: i++
for (let i: number = 1; i <= 10; i++) {
  // Calculate the product for this step
  const product: number = multiplier * i;
  // Print the current line of the table
  console.log(multiplier + ' x ' + i + ' = ' + product);
}
// Expected output:
// 3 x 1 = 3
// 3 x 2 = 6
// ... (up to 3 x 10 = 30)
